fallback() external payable {
    LibDiamond.DiamondStorage storage ds;
    bytes32 position = LibDiamond.DIAMOND_STORAGE_POSITION;
    // get diamond storage
    assembly {
        ds.slot := position
    }
    // get facet from function selector
    address facet = ds.selectorToFacetAndPosition[msg.sig].facetAddress;
    require(facet != address(0), "Diamond: Function does not exist");
    // Execute external function from facet using delegatecall and return any value.
    assembly {
        // copy function selector and any arguments
        calldatacopy(0, 0, calldatasize())
        // execute function call using the facet
        let result := delegatecall(gas(), facet, 0, calldatasize(), 0, 0)
        // get any return value
        returndatacopy(0, 0, returndatasize())
        // return any return value or error back to the caller
        switch result
        case 0 {
            revert(0, returndatasize())
        }
        default {
            return(0, returndatasize())
        }
    }
}

public resolveActions(
  serverState: ServerState,
  diagnostic: Diagnostic,
  context: ResolveActionsContext
): CodeAction[] {
  const missingContractIdentifiers = this.parseContractIdentifiersFromMessage(
    diagnostic.message
  );

  const multiOverride = new Multioverride(missingContractIdentifiers);

  // When no specifier is present, solc sourceLocation covers the whole function body
  // so we can apply the general quickfix for specifiers
  const insertSpecifierQuickfix = resolveInsertSpecifierQuickFix(
    multiOverride,
    diagnostic,
    context,
    serverState.logger
  );

  if (insertSpecifierQuickfix.length > 0) {
    return insertSpecifierQuickfix;
  }

  // If just 'override' or 'override(A)' is present, assuming there are more
  // contracts that need to be specified besides A, solc error sourceLocation only
  // covers the `override(...)` string
  const updateSpecifierQuickfix = this._tryUpdateOverride(
    context,
    diagnostic,
    multiOverride
  );

  if (updateSpecifierQuickfix.length > 0) {
    return updateSpecifierQuickfix;
  }

  return [];
}

public async accept(
  find: FinderType,
  orphanNodes: Node[],
  parent?: Node,
  expression?: Node
): Promise<Node> {
  this.setExpressionNode(expression);

  // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
  if (this.astNode.condition) {
    await (
      await find(
        this.astNode.condition,
        this.uri,
        this.rootPath,
        this.solFileIndex
      )
    ).accept(find, orphanNodes, parent);
  }

  // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
  if (this.astNode.trueExpression) {
    await (
      await find(
        this.astNode.trueExpression,
        this.uri,
        this.rootPath,
        this.solFileIndex
      )
    ).accept(find, orphanNodes, parent);
  }

  // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
  if (this.astNode.falseExpression) {
    await (
      await find(
        this.astNode.falseExpression,
        this.uri,
        this.rootPath,
        this.solFileIndex
      )
    ).accept(find, orphanNodes, parent);
  }

  return this;
}

function signatureHelp(
  document: TextDocument,
  vsCodePosition: VSCodePosition,
  documentAnalyzer: ISolFileEntry,
  logger: Logger
): SignatureHelp | undefined {
  if (documentAnalyzer.text === undefined) {
    return undefined;
  }

  const analyzerTree = documentAnalyzer.analyzerTree.tree;

  const declarationSignature = getDeclarationSignature(
    vsCodePosition,
    document
  );

  if (!declarationSignature) {
    return undefined;
  }

  const definitionNode = documentAnalyzer.searcher.findDefinitionNodeByPosition(
    documentAnalyzer.uri,
    declarationSignature.declarationNodePosition,
    analyzerTree
  );

  if (!definitionNode) {
    return undefined;
  }

  const definitionSignature = getDefinitionSignature(definitionNode, logger);

  if (!definitionSignature) {
    return undefined;
  }

  return {
    signatures: [definitionSignature],
    activeSignature: undefined,
    activeParameter: declarationSignature.activeParameter,
  };
}

async function resolveUserConfig(
  userConfig: HardhatUserConfig,
  resolveConfigurationVariable: ConfigurationVariableResolver,
  next: (
    nextUserConfig: HardhatUserConfig,
    nextResolveConfigurationVariable: ConfigurationVariableResolver,
  ) => Promise<HardhatConfig>,
): Promise<HardhatConfig> {
  const resolvedConfig = await next(userConfig, resolveConfigurationVariable);

  // Add solx debugInfo selectors so the cached solcInput, build-info,
  // and build-ID hash all include them.
  const profiles = await augmentSolxOutputSelectionInProfiles(
    resolvedConfig.solidity.profiles,
  );

  return {
    ...resolvedConfig,
    solidity: {
      ...resolvedConfig.solidity,
      profiles,
      registeredCompilerTypes:
        resolvedConfig.solidity.registeredCompilerTypes.includes(
          SOLX_COMPILER_TYPE,
        )
          ? resolvedConfig.solidity.registeredCompilerTypes
          : [
              ...resolvedConfig.solidity.registeredCompilerTypes,
              SOLX_COMPILER_TYPE,
            ],
    },
    solx: resolveSolxConfig(userConfig.solx),
  };
}

async function getBalanceChange(
  ethers: HardhatEthers,
  transaction: TransactionResponse | Promise<TransactionResponse>,
  token: Token,
  account: Addressable | string,
): Promise<bigint> {
  const txResponse = await transaction;

  const txReceipt = await txResponse.wait();
  assertIsNotNull(
    txReceipt,
    "Transaction's receipt cannot be fetched from the network",
  );
  const txBlockNumber = txReceipt.blockNumber;

  const block = await ethers.provider.getBlock(txReceipt.blockHash, false);

  assertIsNotNull(
    block,
    "The transaction's block cannot be fetched from the network",
  );

  chaiAssert.equal(
    block.transactions.length,
    1,
    "There should be only 1 transaction in the block",
  );

  const address = await getAddressOf(account);

  const balanceAfter = await token.balanceOf(address, {
    blockTag: txBlockNumber,
  });

  const balanceBefore = await token.balanceOf(address, {
    blockTag: txBlockNumber - 1,
  });

  return toBigInt(balanceAfter) - balanceBefore;
}

async function revertedWithCustomErrorWithArgs(
  context: any,
  Assertion: Chai.AssertionStatic,
  _chaiUtils: Chai.ChaiUtils,
  expectedArgs: any[],
  ssfi: Ssfi,
): Promise<void> {
  const negated = false; // .withArgs cannot be negated
  const assert = buildAssert(negated, ssfi);

  const customErrorAssertionData: CustomErrorAssertionData =
    context.customErrorData;

  if (customErrorAssertionData === undefined) {
    chaiAssert.fail(
      "[.withArgs] should never happen, please submit an issue to the Hardhat repository",
    );
  }

  const { contractInterface, customError, returnData } =
    customErrorAssertionData;

  const errorFragment = contractInterface.getError(customError.name);

  assertIsNotNull(
    errorFragment,
    "Error type can't be found in the contract's interface",
  );

  // We transform ether's Array-like object into an actual array as it's safer
  const actualArgs = resultToArray(
    contractInterface.decodeErrorResult(errorFragment, returnData),
  );

  assertArgsArraysEqual(
    Assertion,
    expectedArgs,
    actualArgs,
    `"${customError.name}" custom error`,
    "error",
    assert,
    ssfi,
  );
}

async function initializeEthers(
  ethereumProvider: EthereumProvider,
  networkName: string,
  networkConfig: NetworkConfig,
  artifactManager: ArtifactManager,
): Promise<HardhatEthers> {
  const provider = new HardhatEthersProvider(
    ethereumProvider,
    networkName,
    networkConfig,
  );

  const hardhatHelpers = new HardhatHelpers(
    provider,
    networkName,
    networkConfig,
    artifactManager,
  );

  return {
    ...ethers,

    provider,

    // The bind is necessary because otherwise in the function the "this" that refers to the HardhatHelpers class will be overwritten
    getSigner: hardhatHelpers.getSigner.bind(hardhatHelpers),
    getSigners: hardhatHelpers.getSigners.bind(hardhatHelpers),
    getImpersonatedSigner:
      hardhatHelpers.getImpersonatedSigner.bind(hardhatHelpers),
    getContractFactory: hardhatHelpers.getContractFactory.bind(hardhatHelpers),
    getContractFactoryFromArtifact:
      hardhatHelpers.getContractFactoryFromArtifact.bind(hardhatHelpers),
    getContractAt: hardhatHelpers.getContractAt.bind(hardhatHelpers),
    getContractAtFromArtifact:
      hardhatHelpers.getContractAtFromArtifact.bind(hardhatHelpers),
    deployContract: hardhatHelpers.deployContract.bind(hardhatHelpers),
  };
}

public merge(
  other: DependencyGraphImplementation,
): DependencyGraphImplementation {
  const merged = new DependencyGraphImplementation();

  for (const [userSourceName, root] of this.#rootByUserSourceName) {
    merged.addRootFile(userSourceName, root);
  }

  for (const [userSourceName, root] of other.#rootByUserSourceName) {
    if (merged.hasFile(root)) {
      continue;
    }
    merged.addRootFile(userSourceName, root);
  }

  for (const [from, dependencies] of this.#dependenciesMap) {
    for (const [to, remappings] of dependencies) {
      merged.addDependency(from, to);

      for (const remapping of remappings) {
        merged.addDependency(from, to, remapping);
      }
    }
  }

  for (const [from, dependencies] of other.#dependenciesMap) {
    for (const [to, remappings] of dependencies) {
      merged.addDependency(from, to);

      for (const remapping of remappings) {
        merged.addDependency(from, to, remapping);
      }
    }
  }

  return merged;
}

function shouldUpdateDependency(
  workspaceVersion: string | undefined,
  templateVersion: string,
): boolean {
  // We should not update the dependency if it is not yet installed in the workspace.
  if (workspaceVersion === undefined) {
    return false;
  }
  // NOTE: a specific version also a valid range that includes itself only
  const workspaceRange = semver.validRange(workspaceVersion, {
    includePrerelease: true,
  });
  const templateRange = semver.validRange(templateVersion, {
    includePrerelease: true,
  });
  assertHardhatInvariant(
    templateRange !== null,
    "All dependencies of the template should have valid versions",
  );
  // We should update the dependency if the workspace version could not be parsed.
  if (workspaceRange === null) {
    return true;
  }
  // We should update the dependency if the workspace range (or, in particular, a specific version) is not
  // a strict subset of the template range/does not equal the template version.
  return !semver.subset(workspaceRange, templateRange, {
    includePrerelease: true,
  });
}

async function resolveReadEventArgumentResult(
  future: Future,
  emitter: ContractFuture<string>,
  eventName: string,
  eventIndex: number,
  nameOrIndex: string | number,
  deploymentState: DeploymentState,
  deploymentLoader: DeploymentLoader,
): Promise<{
  result: SolidityParameterType;
  emitterAddress: string;
  txToReadFrom: string;
}> {
  const emitterAddress = resolveAddressForContractFuture(
    emitter,
    deploymentState,
  );

  const emitterArtifact = await deploymentLoader.loadArtifact(emitter.id);

  const confirmedTx = findConfirmedTransactionByFutureId(
    deploymentState,
    future.id,
  );

  const evmValue = getEventArgumentFromReceipt(
    confirmedTx.receipt,
    emitterArtifact,
    emitterAddress,
    eventName,
    eventIndex,
    nameOrIndex,
  );

  return {
    result: convertEvmValueToSolidityParam(evmValue),
    emitterAddress,
    txToReadFrom: confirmedTx.hash,
  };
}

function createExecutionStateCompleteMessageForExecutionsWithOnchainInteractions(
  exState:
    | DeploymentExecutionState
    | CallExecutionState
    | SendDataExecutionState,
  result:
    | DeploymentExecutionResult
    | CallExecutionResult
    | SendDataExecutionResult,
):
  | DeploymentExecutionStateCompleteMessage
  | CallExecutionStateCompleteMessage
  | SendDataExecutionStateCompleteMessage {
  switch (exState.type) {
    case ExecutionSateType.DEPLOYMENT_EXECUTION_STATE:
      return {
        type: JournalMessageType.DEPLOYMENT_EXECUTION_STATE_COMPLETE,
        futureId: exState.id,
        result: result as DeploymentExecutionResult,
      };

    case ExecutionSateType.CALL_EXECUTION_STATE:
      return {
        type: JournalMessageType.CALL_EXECUTION_STATE_COMPLETE,
        futureId: exState.id,
        result: result as CallExecutionResult,
      };

    case ExecutionSateType.SEND_DATA_EXECUTION_STATE:
      return {
        type: JournalMessageType.SEND_DATA_EXECUTION_STATE_COMPLETE,
        futureId: exState.id,
        result: result as SendDataExecutionResult,
      };
  }
}

async function replayStrategy(
  executionState:
    | DeploymentExecutionState
    | CallExecutionState
    | SendDataExecutionState
    | StaticCallExecutionState,
  strategy: ExecutionStrategy,
): Promise<
  | DeploymentStrategyGenerator
  | CallStrategyGenerator
  | SendDataStrategyGenerator
  | StaticCallStrategyGenerator
> {
  switch (executionState.type) {
    case ExecutionSateType.DEPLOYMENT_EXECUTION_STATE:
      return await replayExecutionStrategyWithOnchainInteractions(
        executionState,
        strategy,
      );
    case ExecutionSateType.CALL_EXECUTION_STATE:
      return await replayExecutionStrategyWithOnchainInteractions(
        executionState,
        strategy,
      );
    case ExecutionSateType.SEND_DATA_EXECUTION_STATE:
      return await replayExecutionStrategyWithOnchainInteractions(
        executionState,
        strategy,
      );
    case ExecutionSateType.STATIC_CALL_EXECUTION_STATE:
      return await replayStaticCallExecutionStrategy(executionState, strategy);
  }
}

function convertExecutionResultToEventResult(
  result:
    | DeploymentExecutionResult
    | CallExecutionResult
    | SendDataExecutionResult,
): ExecutionEventResult {
  switch (result.type) {
    case ExecutionResultType.SUCCESS: {
      return {
        type: ExecutionEventResultType.SUCCESS,
        result: "address" in result ? result.address : undefined,
      };
    }
    case ExecutionResultType.STATIC_CALL_ERROR:
    case ExecutionResultType.SIMULATION_ERROR: {
      return {
        type: ExecutionEventResultType.ERROR,
        error: failedEvmExecutionResultToErrorDescription(result.error),
      };
    }
    case ExecutionResultType.STRATEGY_ERROR:
    case ExecutionResultType.STRATEGY_SIMULATION_ERROR: {
      return {
        type: ExecutionEventResultType.ERROR,
        error: result.error,
      };
    }
    case ExecutionResultType.REVERTED_TRANSACTION: {
      return {
        type: ExecutionEventResultType.ERROR,
        error: "Transaction reverted",
      };
    }
    case ExecutionResultType.STRATEGY_HELD: {
      return {
        type: ExecutionEventResultType.HELD,
        heldId: result.heldId,
        reason: result.reason,
      };
    }
  }
}

public static async reconcile(
  module: IgnitionModule,
  deploymentState: DeploymentState,
  deploymentParameters: DeploymentParameters,
  accounts: string[],
  deploymentLoader: DeploymentLoader,
  artifactResolver: ArtifactResolver,
  defaultSender: string,
  strategy: string,
  strategyConfig: ConcreteExecutionConfig,
): Promise<ReconciliationResult> {
  const reconciliationFailures = await this._reconcileEachFutureInModule(
    module,
    {
      deploymentState,
      deploymentParameters,
      accounts,
      deploymentLoader,
      artifactResolver,
      defaultSender,
      strategy,
      strategyConfig,
    },
    [
      reconcileCurrentAndPreviousTypeMatch,
      reconcileDependencyRules,
      reconcileFutureSpecificReconciliations,
    ],
  );

  // TODO: Reconcile sender of incomplete futures.

  const missingExecutedFutures = this._missingPreviouslyExecutedFutures(
    module,
    deploymentState,
  );

  return { reconciliationFailures, missingExecutedFutures };
}
